module top_module(npc, wpcir, clock, resetn, pc);input   [31:0]  npc;
    input           clock, resetn, wpcir;

    output  [31:0]  pc;
  wire [31:0] _tap_npc = npc & {32{1'b1}};


    reg     [31:0]  pcreg;

    assign pc = pcreg;

    always @ (posedge clock or negedge resetn) begin
		if (resetn == 0) begin
            pcreg <= -4;
        end else if (wpcir == 0) begin
			pcreg <= npc;
		end else begin
			pcreg <= pcreg;
		end
    end
endmodule
